<?php
require_once dirname(__DIR__).'/helpers.php';require_admin();$pageTitle='Verifikasi Donasi';
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$id=(int)$_POST['id'];$status=$_POST['status'];if(in_array($status,['verified','rejected'],true)){$stmt=db()->prepare('UPDATE donations SET status=?,verified_at=? WHERE id=?');$stmt->execute([$status,$status==='verified'?date('Y-m-d H:i:s'):null,$id]);flash('success','Status donasi diperbarui.');redirect('admin/donations.php');}}
$status=$_GET['status']??'';$sql="SELECT d.*,c.title campaign_title FROM donations d JOIN campaigns c ON c.id=d.campaign_id";$params=[];if(in_array($status,['pending','verified','rejected'],true)){$sql.=' WHERE d.status=?';$params[]=$status;}$sql.=" ORDER BY CASE d.status WHEN 'pending' THEN 0 ELSE 1 END,d.created_at DESC";$stmt=db()->prepare($sql);$stmt->execute($params);$rows=$stmt->fetchAll();include dirname(__DIR__).'/partials/header.php';include __DIR__.'/nav.php';?>
<section class="admin-content container"><div class="admin-heading"><div><span class="eyebrow">Administrasi</span><h1>Verifikasi Donasi</h1></div><div class="pills"><a href="?">Semua</a><a href="?status=pending">Pending</a><a href="?status=verified">Terverifikasi</a><a href="?status=rejected">Ditolak</a></div></div><div class="donation-admin-list"><?php foreach($rows as $d):?><article class="glass admin-donation <?=((int)($_GET['focus']??0)===$d['id'])?'focused':''?>"><div><span class="status <?=e($d['status'])?>"><?=e($d['status'])?></span><h3><?=e($d['donor_name'])?> · <?=money((float)$d['amount'])?></h3><p><?=e($d['campaign_title'])?></p><small><?=e($d['email'])?> · <?=date('d/m/Y H:i',strtotime($d['created_at']))?></small><?php if($d['message']):?><blockquote>“<?=e($d['message'])?>”</blockquote><?php endif;?></div><div class="proof-box"><?php if($d['proof_file']):?><a class="btn ghost" target="_blank" href="<?=url('admin/proof.php?id='.$d['id'])?>">Lihat Bukti Transfer</a><?php endif;?><a class="text-link" target="_blank" href="<?=url('receipt.php?code='.urlencode($d['receipt_code']))?>">Lihat bukti donasi</a></div><?php if($d['status']==='pending'):?><form method="post" class="verify-actions"><?=csrf_field()?><input type="hidden" name="id" value="<?=$d['id']?>"><button class="btn primary" name="status" value="verified">Verifikasi</button><button class="btn danger" name="status" value="rejected">Tolak</button></form><?php endif;?></article><?php endforeach;?></div></section>
<?php include dirname(__DIR__).'/partials/footer.php'; ?>
